import{_ as t,a,b as r,c as i}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as s,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Utiliser les liens magnet","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/magnet-transfer.md","filePath":"fr-FR/Other/magnet-transfer.md","lastUpdated":1781962217000}'),o={name:"fr-FR/Other/magnet-transfer.md"};function c(m,e,u,h,p,g){return s(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="utiliser-les-liens-magnet" tabindex="-1">Utiliser les liens magnet <a class="header-anchor" href="#utiliser-les-liens-magnet" aria-label="Permalink to &quot;Utiliser les liens magnet&quot;">​</a></h1><p>La fonction de transfert magnet télécharge les fichiers contenus dans un lien magnet, puis les envoie automatiquement vers le canal de stockage choisi.</p><p>Elle convient pour transférer des vidéos, des épisodes, des archives compressées ou d’autres fichiers. Il suffit de coller le lien magnet : ImgBed crée une tâche en arrière-plan et affiche le lien final dans la liste des téléversements une fois le traitement terminé.</p><p><img src="'+t+'" alt="Lien magnet" loading="lazy"></p><h2 id="ou-l-utiliser" tabindex="-1">Où l’utiliser <a class="header-anchor" href="#ou-l-utiliser" aria-label="Permalink to &quot;Où l’utiliser&quot;">​</a></h2><p>L’entrée se trouve dans la zone de téléversement de la page d’accueil.</p><p>Collez le lien magnet dans le champ, choisissez le mode <code>Transférer</code>, puis lancez le téléversement.</p><p><img src="'+a+'" alt="Téléversement magnet" loading="lazy"></p><h2 id="avant-de-commencer" tabindex="-1">Avant de commencer <a class="header-anchor" href="#avant-de-commencer" aria-label="Permalink to &quot;Avant de commencer&quot;">​</a></h2><p>Configurez d’abord le transfert magnet dans le panneau d’administration.</p><p>Vous aurez généralement besoin de :</p><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte GitHub</td><td>Exécuter la tâche de téléchargement</td></tr><tr><td>Canal de téléversement</td><td>Destination finale, comme Google Drive ou OneDrive</td></tr><tr><td>Dossier de destination</td><td>Emplacement où enregistrer le fichier transféré</td></tr><tr><td>Délai limite</td><td>Limite pour les tâches longues</td></tr></tbody></table><h2 id="transferer-un-magnet" tabindex="-1">Transférer un magnet <a class="header-anchor" href="#transferer-un-magnet" aria-label="Permalink to &quot;Transférer un magnet&quot;">​</a></h2><ol><li>Collez le lien magnet dans le champ de téléversement de la page d’accueil.</li><li>Vérifiez que le mode est <code>Transférer</code>.</li><li>Cliquez sur téléverser.</li><li>Attendez que la tâche soit créée.</li><li>Suivez la progression dans la fenêtre <code>Tâches magnet</code>, en bas à droite.</li></ol><p>Le téléchargement et l’envoi peuvent prendre du temps. La vitesse dépend de la disponibilité du magnet, de l’environnement d’exécution GitHub et du canal de stockage choisi.</p><p><img src="'+r+'" alt="Téléchargement en cours" loading="lazy"></p><h2 id="apres-la-fin-de-la-tache" tabindex="-1">Après la fin de la tâche <a class="header-anchor" href="#apres-la-fin-de-la-tache" aria-label="Permalink to &quot;Après la fin de la tâche&quot;">​</a></h2><p>Lorsque la tâche est terminée, la liste des téléversements affiche le nom du fichier et ses liens.</p><p>Les vidéos ont une prévisualisation vidéo, les images une prévisualisation d’image, et les autres fichiers un simple pictogramme.</p><p><img src="'+i+'" alt="Vidéo transférée" loading="lazy"></p><p>Vous pouvez copier ces formats :</p><table tabindex="0"><thead><tr><th>Format</th><th>Usage</th></tr></thead><tbody><tr><td>Lien original</td><td>Ouvrir directement le fichier</td></tr><tr><td>Markdown</td><td>Insérer dans un article ou une documentation Markdown</td></tr><tr><td>HTML</td><td>Insérer dans le code d’une page web</td></tr><tr><td>BBCode</td><td>Utiliser sur un forum compatible BBCode</td></tr></tbody></table><h2 id="etats-de-tache" tabindex="-1">États de tâche <a class="header-anchor" href="#etats-de-tache" aria-label="Permalink to &quot;États de tâche&quot;">​</a></h2><table tabindex="0"><thead><tr><th>État</th><th>Signification</th></tr></thead><tbody><tr><td>En attente</td><td>La tâche est créée et attend son exécution</td></tr><tr><td>Téléchargement</td><td>La ressource magnet est en cours de téléchargement</td></tr><tr><td>Envoi</td><td>Le fichier téléchargé est envoyé vers le canal</td></tr><tr><td>Terminé</td><td>L’envoi est terminé et le lien peut être copié</td></tr><tr><td>Échec</td><td>Consultez le message et relancez si nécessaire</td></tr></tbody></table><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Si le magnet contient plusieurs fichiers, ImgBed met en avant le fichier principal terminé.</li><li>Les gros fichiers demandent plus de temps ; attendez la fin de la tâche avant de recharger la page.</li><li>Si la ressource n’a pas de sources disponibles, le téléchargement peut être très lent ou échouer.</li><li>Si le compte de stockage manque de quota, de droits ou de dossier correct, l’envoi peut échouer.</li><li>La prévisualisation vidéo peut mettre quelques secondes à se charger.</li></ul>',26)])])}const _=n(o,[["render",c]]);export{b as __pageData,_ as default};
